const fed = $('Get Federation').first().json;
const dirs = Array.isArray(fed.directory_urls) ? fed.directory_urls : [];
const api = dirs.find(d => d && d.extraction_method === 'api_endpoint' && /^https?:\/\//.test(d.url || ''));
if (!api) return [{ json: { __skip: true, note: 'no api_endpoint directory for this federation' } }];

const res = await this.helpers.httpRequest({
  method: 'GET', url: api.url, headers: { 'User-Agent': 'Mozilla/5.0 (compatible; leblovina-n8n)' }, json: true,
});

// Deterministically find the largest array of plain objects anywhere in the response.
let best = [];
const walk = (o) => {
  if (Array.isArray(o)) {
    if (o.length > best.length && o.every(x => x && typeof x === 'object' && !Array.isArray(x))) best = o;
    for (const x of o) walk(x);
  } else if (o && typeof o === 'object') {
    for (const k of Object.keys(o)) walk(o[k]);
  }
};
walk(res);

const sample = best.slice(0, 2);
const keys = best.length ? Object.keys(best[0]) : [];
return [{ json: { sourceUrl: api.url, count: best.length, keys, sample, clubs: best } }];

